/** The four entry types — drive direction, category set, and the chargeback
 *  dispute reveal (model spec §8.3). */
export type EntryType = "expense" | "revenue" | "draw" | "chargeback";

/** Chargeback disposition — only shown when type === "chargeback". */
export type Disposition = "dispute" | "accept";

/** Payment-terms segment in the "More detail" disclosure. */
export type Terms = "now" | "net15" | "net30" | "net60";

/** VAT treatment segment. */
export type VatTreatment = "none" | "incl" | "excl";

/** Currency segment (home vs foreign → reveals FX rate). */
export type CurrencyMode = "home" | "fx";

export interface LogEntryData {
  /** Spendable cash before this entry posts — the read computes "after". */
  cashNow: number;
  /** Gateway fee booked on a chargeback (revenue reversal + fee expense). */
  chargebackFee: number;
  /** Category options for the visible Category dropdown (expense path). */
  categoryOptions: string[];
  /** Category options used inside split-entry rows (superset incl. fees/tax). */
  splitCategoryOptions: string[];
  /** Entity-link options — connects the entry to PO / supplier / campaign. */
  linkOptions: string[];
  /** Net-terms options for the payment-terms segment, with read labels. */
  termsOptions: { value: Terms; label: string; readLabel: string }[];
  /** Demo values the drop-to-fill auto-fill uses (a receipt being read). */
  dropFill: {
    fileName: string;
    amount: string;
    date: string;
    method: string;
    category: string;
  };
  /** Seed row used when the founder opens the split-entry allocator. */
  splitSeed: { cat: string; amt: string };
}

